INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0604270N$$, 2027, $$This program element includes development of Electronic Warfare (EW) systems for the United States Navy (USN), United States Marine Corps (USMC), and United
States Army tactical aircraft, USMC helicopters, surface combatants, data link vulnerability assessments, precision targeting, USN and USMC radio frequency jammers,
and development and testing of EW devices for emerging threats and emergency contingencies. This element also includes: development of hardware (HW)/software
(SW) solutions that link on-board integrated Aircraft Survivability Equipment (iASE) that are compatible with mission planning information and systems; studies, analysis
and evaluations of current and future aircraft threats; modeling and simulation for improved countermeasure capabilities, and development and testing to address new
and emerging threats. The projects in this element improve the ability of the Joint Force to strike diverse targets inside adversary air and missile defense networks to
destroy mobile power-projection platforms and enhance close combat lethality in complex terrain.

 This program is funded under System Development and Demonstration because it includes those projects that have passed Milestone B approval and are conducting
 Engineering and Manufacturing Development (EMD) tasks aimed at meeting validated requirements prior to Full-Rate Production (FRP) decision.
Development & Demonstration (SDD)$$, $$This project unit supports the United States Marine Corps (USMC) development of Marine Air Ground Task Force (MAGTF) Electronic Warfare (EW) and the various
elements of its distributed System of Systems (SoS). The SoS addresses MAGTF EW sufficiency gaps in the areas of Electronic Attack (EA) and Electronic Warfare
Support (ES) with a multitude of payloads designed for carriage on a variety of organic MAGTF air assets. Payload development plans follow an adaptable, modular
and open architecture philosophy to combat the increasing capability gap and enable future growth at a reduced operational and sustainment cost. A key element to this
capability is the AN/ALQ-231(V) Intrepid Tiger II program.

 The AN/ALQ-231(V)1 pod is the variant of the Intrepid Tiger II pod flown on the AV-8B, F/A-18A-D, and KC-130J platforms. The AN/ALQ-231(V)3 is the variant of the
 Intrepid Tiger II pod flown on the UH-1Y platform, with plans for integration on AH-1Z platforms. (V)3 Blk 2 is an Engineering Change Proposal (ECP) to the original
 (V)3, providing additional capability to address evolving threats. Plans include future integration of AN/ALQ-231(V) Block X advanced capability and counter-radar
 upgrades on USMC tilt rotor, fixed wing, rotary wing and unmanned aircraft. The AN/ALQ-231(V)4 is the first implementation of Block X upgrades on MV-22B aircraft and
 future (V)5 BLK X integration may occur on platforms such as, but not limited to, the KC-130J, MQ-9, CH-53K, and AH-1Z platforms. All payload variants are capable
 of conducting, supporting, and coordinating Electro-Magnetic Spectrum (EMS) operations in the form of EA and ES against Irregular Warfare threats. Additionally, all
 payloads are scalable and adaptable for emerging threats and are interoperable with the USMC's Electronic Warfare Services Architecture (EWSA). The Intrepid Tiger II
 capability is designed to be integrated for MAGTF tactical coordination of cyberspace and EW operations via the Cyber Electronic Warfare Coordination Cell (CEWCC).

